head.script:
/*  */
{
  "@context": "https://schema.org",
  "@graph": [
    {
      "@type": "WebSite",
      "@id": "https://masonsweather.com/",
      "url": "https://masonsweather.com/",
      "name": "Mason's Weather Network",
      "description": "Decentralized Microclimate Systems and weather telemetry portal.",
      "publisher": {
        "@id": "https://masonsweather.com/"
      }
    },
    {
      "@type": "Organization",
      "@id": "https://masonsweather.com/",
      "name": "Mason's Weather Network",
      "url": "https://masonsweather.com/",
      "logo": "https://masonsweather.com/images/Mason's Weather Logo.png",
      "knowsAbout": [
        "Meteorology",
        "Climatology",
        "Microclimates",
        "Weather Forecasting"
      ],
      "knowsLanguage": ["en"],
      "sponsor": [
        {
          "@type": "GovernmentOrganization",
          "name": "National Oceanic and Atmospheric Administration",
          "alternateName": "NOAA",
          "url": "https://www.noaa.gov/"
        },
        {
          "@type": "GovernmentOrganization",
          "name": "National Weather Service",
          "alternateName": "NWS",
          "url": "https://www.weather.gov/"
        }
      ]
    },
    {
      "@type": "Person",
      "@id": "https://masonramirez.net",
      "name": "Mason Ramirez",
      "jobTitle": "Broadcast Director",
      "worksFor": {
        "@id": "https://nascar.com"
      },
      "knowsAbout": [
        "Meteorology",
        "Weather Broadcasting",
        "Data Analytics",
        "Broadcast Directing",
        "Broadcast",
        "Racing",
        "NASCAR"
      ]
    },
    {
      "@type": "ItemList",
      "@id": "https://masonsweather.com/sitemap.xml",
      "name": "Mason's Weather Network Directory",
      "numberOfItems": 3,
      "itemListElement": [
        {
          "@type": "ListItem",
          "position": 1,
          "item": {
            "@type": "WebPage",
            "@id": "https://masonsweather.com/",
            "url": "https://masonsweather.com/",
            "name": "Mason's Weather Portal - Home",
            "description": "Unified entry point for coastal and desert weather monitoring centers.",
            "author": {
              "@id": "https://masonramirez.net"
            }
          }
        },
        {
          "@type": "ListItem",
          "position": 2,
          "item": {
            "@type": "WebPage",
            "@id": "https://masonsweather.com/southbay",
            "url": "https://masonsweather.com/southbay",
            "name": "South Bay Masons Weather Station",
            "description": "Marine meteorology and coastal wave telemetry for South Bay cities.",
            "author": {
              "@id": "https://masonramirez.net"
            },
            "spatialCoverage": [
              {
                "@type": "City",
                "name": "Redondo Beach",
                "sameAs": "https://en.wikipedia.org/wiki/Redondo_Beach,_California"
              },
              {
                "@type": "City",
                "name": "Hermosa Beach",
                "sameAs": "https://en.wikipedia.org/wiki/Hermosa_Beach,_California"
              },
              {
                "@type": "City",
                "name": "Manhattan Beach",
                "sameAs": "https://en.wikipedia.org/wiki/Manhattan_Beach,_California"
              },
              {
                "@type": "City",
                "name": "Palos Verdes",
                "sameAs": "https://en.wikipedia.org/wiki/Palos_Verdes_Estates,_California"
              }
            ]
          }
        },
        {
          "@type": "ListItem",
          "position": 3,
          "item": {
            "@type": "WebPage",
            "@id": "https://masonsweather.com/mohavecounty",
            "url": "https://masonsweather.com/mohavecounty",
            "name": "Mojave County Weather Station",
            "description": "High-altitude and desert microclimates tracking Mojave County regions.",
            "author": {
              "@id": "https://masonramirez.net"
            },
            "spatialCoverage": [
              {
                "@type": "City",
                "name": "Kingman",
                "sameAs": "https://en.wikipedia.org/wiki/Kingman,_Arizona"
              },
              {
                "@type": "City",
                "name": "Hualapai Peak",
                "sameAs": "https://en.wikipedia.org/wiki/Hualapai_Peak"
              },
              {
                "@type": "City",
                "name": "Lake Havasu City",
                "sameAs": "https://en.wikipedia.org/wiki/Lake_Havasu_City,_Arizona"
              },
              {
                "@type": "City",
                "name": "Bullhead City",
                "sameAs": "https://en.wikipedia.org/wiki/Bullhead_City,_Arizona"
              },
              {
                "@type": "City",
                "name": "Wikieup",
                "sameAs": "https://en.wikipedia.org/wiki/Wikieup,_Arizona"
              }
            ]
          }
        }
      ]
    }
  ]
}
/*  */
